{
  "room": {
    "idSlug": "the-commons-west",
    "name": "The Commons - High Market",
    "description": "This vast, vaulted space was once the ship's social heartbeat, now muffled under heavy dust cloths and long shadows. Multi-level stalls and modular homes are built directly into the ship's hull, their facades decorated with fading murals and hanging bead curtains. A central fountain, now dry, is filled with a soft, bioluminescent moss that provides the only light in the gloom.",
    "tags": [
      "room",
      "ship-interior",
      "region"
    ],
    "properties": {
      "systemStatus": "degraded",
      "takeRefusal": "The space is too vast to move."
    },
    "additionalExits": [
      {
        "direction": "northwest",
        "name": "The Weaving District",
        "description": "A narrower street leads toward a section draped in thousands of swaying, multi-colored strands.",
        "aliases": [
          "weaving",
          "district"
        ],
        "properties": {
          "accessLevel": 0
        },
        "destinationIntent": "A residential and artisanal area focused on textiles and vertical living, filled with rope bridges and hanging looms."
      },
      {
        "direction": "south",
        "name": "The Low Tier Stepped Way",
        "description": "Broad, shallow stairs descend toward a lower level where the air feels cooler and smells of damp earth.",
        "aliases": [
          "stairs",
          "steps",
          "down"
        ],
        "properties": {
          "accessLevel": 0
        },
        "destinationIntent": "A lower-level marketplace or garden area of the Commons, perhaps more industrial or agricultural."
      }
    ],
    "contents": [
      {
        "idSlug": "dust-covered-cart",
        "idCategory": "container",
        "name": "Merchant's Push-Cart",
        "description": "A wooden cart with wheels made from recycled gear-teeth, draped in a heavy, grey canvas. Through the gaps in the cloth, you can see rows of small glass jars and what looks like dried botanical specimens.",
        "tags": [
          "container",
          "openable"
        ],
        "aliases": [
          "cart",
          "wagon",
          "cloth"
        ],
        "properties": {
          "open": false,
          "shortDescription": "a canvas-draped merchant's cart",
          "takeRefusal": "It's far too heavy to push through the dust."
        }
      },
      {
        "idSlug": "moss-fountain-inscription",
        "idCategory": "fixed-display",
        "name": "Fountain Inscription",
        "description": "Around the rim of the dry fountain, letters have been painstakingly hammered into the metal. The moss glows brighter when you lean close.",
        "tags": [
          "fixed-display"
        ],
        "aliases": [
          "fountain",
          "inscription",
          "writing"
        ],
        "properties": {
          "fixed": true,
          "takeRefusal": "The inscription is part of the fountain's heavy rim.",
          "worn": false
        }
      }
    ],
    "exitUpdate": {
      "name": "Archway to Junction C-7"
    },
    "imagePrompt": "A massive, dark vaulted plaza inside a ship, illuminated by patches of glowing blue moss in a dry fountain. Ghostly shapes of furniture covered in grey dust cloths sit between colorful, tiered market stalls with hand-painted signs. The scale is immense, like a town square moved indoors, with balconies overlooking the space.",
    "returnExitDescription": "The passage back to the junction is marked by a tall, elegant archway of hammered copper.",
    "returnExitName": "The Copper Arch",
    "secret": "The moss in the fountain is sensitive to sound. If the player 'sings' or makes noise, the moss pulses with light, briefly illuminating a hidden map carved into the ceiling of the plaza."
  },
  "notes": "Introduced the Commons as a grand, multi-faction space that has transitioned from institutional to a lived-in, village-like atmosphere. The moss provides a natural, eerie light source consistent with the 'divergent tech' feel."
}

object.code:
if (!indirect) {
  return lib.result("What are you aiming at?");
}

var output = "You vigorously crank the handle of the Gurgling Bubble-Thrower. With a series of wet, rhythmic pops, a stream of shimmering, viscous bubbles erupts from the brass bell and drifts toward the " + lib.ref(indirect) + ".";

if (indirect.id === "fixed-display:moss-fountain-inscription") {
  output += " The bubbles stick to the glowing moss, wobbling and reflecting the faint green light like tiny, iridescent lanterns before slowly popping one by one. The moss doesn't seem to mind the bath.";
} else {
  output += " They bounce gently off the surface, wobbling in the air before eventually bursting into small clouds of sweet-smelling vapor.";
}

return lib.result(output);

